import React, { useState, useEffect } from "react";
import { useParams, useNavigate } from "react-router-dom";
import Navbar from "./Navbar";
import Footer from "./Footer";

function Doctorprofile() {
  const { doctor_id } = useParams();
  const navigate = useNavigate();

  const [doctor, setDoctor] = useState(null);
  const [availableDays, setAvailableDays] = useState([]);
  const [availableTimes, setAvailableTimes] = useState([]);
  const [date, setDate] = useState("");
  const [time, setTime] = useState("");

  const [feedbacks, setFeedbacks] = useState([]);
  const [rating, setRating] = useState("");
  const [comment, setComment] = useState("");

  // ✅ POPUP STATE
  const [popup, setPopup] = useState({ show: false, message: "" });

  useEffect(() => {
    fetch(`http://127.0.0.1:8000/doctor-details/${doctor_id}/`, {
      headers: {
        Authorization: `Token ${localStorage.getItem("token")}`,
      },
    })
      .then((res) => res.json())
      .then((data) => {
        setDoctor(data.doctor);
        setAvailableDays(data.doctor.available_days || []);
        setAvailableTimes(data.doctor.available_time_slots || []);
      });
  }, [doctor_id]);

  useEffect(() => {
    fetch(`http://127.0.0.1:8000/doctor-feedback/${doctor_id}/`, {
      headers: {
        Authorization: `Token ${localStorage.getItem("token")}`,
      },
    })
      .then((res) => res.json())
      .then((data) => setFeedbacks(data));
  }, [doctor_id]);

  const avgRating =
    feedbacks.length > 0
      ? (
          feedbacks.reduce((sum, fb) => sum + fb.rating, 0) /
          feedbacks.length
        ).toFixed(1)
      : 0;

  const getDayName = (dateStr) =>
    new Date(dateStr).toLocaleDateString("en-US", {
      weekday: "long",
    });

  const handleDateChange = (e) => {
    const selectedDate = e.target.value;
    const dayName = getDayName(selectedDate);

    if (!availableDays.includes(dayName)) {
      setPopup({
        show: true,
        message: `Doctor not available on ${dayName}`,
      });
      setDate("");
      return;
    }

    setDate(selectedDate);
  };

  // ⭐ REPLACED ALERT WITH POPUP
  const handleNext = () => {
    if (!date || !time) {
      setPopup({
        show: true,
        message: "Please select date and time",
      });
      return;
    }

    navigate("/appointment", {
      state: { doctor, date, time, doctor_id },
    });
  };

  const handleSubmitFeedback = () => {
    if (!rating || !comment) {
      setPopup({
        show: true,
        message: "Please add rating and comment",
      });
      return;
    }

    fetch(`http://127.0.0.1:8000/doctor-feedback/${doctor_id}/`, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        Authorization: `Token ${localStorage.getItem("token")}`,
      },
      body: JSON.stringify({ rating, comment }),
    })
      .then((res) => res.json())
      .then((data) => {
        setFeedbacks([data, ...feedbacks]);
        setRating("");
        setComment("");
      });
  };

  if (!doctor) return <h2 style={styles.loading}>Loading...</h2>;

  return (
    <div style={styles.container}>
      <Navbar />

      {/* ✅ POPUP MODAL */}
      {popup.show && (
        <div style={styles.overlay}>
          <div style={styles.popupCard}>
            <h3>⚠️ Notice</h3>
            <p>{popup.message}</p>
            <button
              style={styles.popupBtn}
              onClick={() => setPopup({ show: false, message: "" })}
            >
              OK
            </button>
          </div>
        </div>
      )}

      <div style={styles.main}>
        <div style={styles.card}>
          <div style={styles.left}>
            <img
              src={
                doctor.image ||
                "https://cdn-icons-png.flaticon.com/512/387/387561.png"
              }
              alt={doctor.name}
              style={styles.image}
            />
          </div>

          <div style={styles.right}>
            <h2>{doctor.name}</h2>
            <p><b>Specialization:</b> {doctor.field}</p>
            <p><b>Experience:</b> {doctor.experience}</p>
            <p><b>Qualification:</b> {doctor.qualification}</p>

            <div style={styles.bookingSection}>
              <label>Select Date:</label>
              <input
                type="date"
                value={date}
                onChange={handleDateChange}
                style={styles.input}
              />

              <label>Select Time:</label>
              <select
                value={time}
                onChange={(e) => setTime(e.target.value)}
                style={styles.input}
              >
                <option value="">Select Time</option>
                {availableTimes.map((t, i) => (
                  <option key={i}>{t}</option>
                ))}
              </select>

              <button style={styles.button} onClick={handleNext}>
                Book Appointment
              </button>
            </div>
          </div>
        </div>
      </div>

      <Footer />
    </div>
  );
}

export default Doctorprofile;

/* 🎨 STYLES */
const styles = {
  container: { display: "flex", flexDirection: "column", minHeight: "100vh", background: "#f4f6f9" },
  main: { flex: 1, display: "flex", justifyContent: "center", alignItems: "center" },
  card: { display: "flex", background: "#fff", padding: "30px", borderRadius: "10px", width: "750px", gap: "30px" },
  left: { display: "flex", alignItems: "center" },
  image: { width: "150px", height: "150px", borderRadius: "50%" },
  right: { flex: 1 },

  bookingSection: { marginTop: "20px", display: "flex", flexDirection: "column", gap: "10px" },
  input: { padding: "8px", borderRadius: "5px", border: "1px solid #ccc" },
  button: { padding: "10px", background: "#2c3e50", color: "#fff", border: "none", borderRadius: "5px" },

  loading: { textAlign: "center", marginTop: "50px" },

  /* ✅ POPUP */
  overlay: {
    position: "fixed",
    top: 0,
    left: 0,
    width: "100%",
    height: "100%",
    background: "rgba(0,0,0,0.5)",
    display: "flex",
    justifyContent: "center",
    alignItems: "center",
    zIndex: 9999,
  },

  popupCard: {
    background: "#fff",
    padding: "25px",
    borderRadius: "10px",
    textAlign: "center",
    width: "300px",
    boxShadow: "0 10px 25px rgba(0,0,0,0.2)",
  },

  popupBtn: {
    marginTop: "15px",
    padding: "8px 20px",
    background: "#2c3e50",
    color: "#fff",
    border: "none",
    borderRadius: "5px",
    cursor: "pointer",
  },
};
